customCss:
/* Dyslexia spacing + OpenDyslexic fallback */
:root {
  --word-spacing: 3px;
  --letter-spacing: 0.25px;
  --message-line-spacing: 2;
}
::-webkit-input-placeholder, body, button, input, select, textarea {
    word-spacing: var(--word-spacing) !important;
    letter-spacing: var(--letter-spacing) !important;
}
[class*="messageContent-"] {
    line-height: var(--message-line-spacing) !important;
}
/* Scale timestamps */
[class*="group-spacing"] [class*="timestamp"],
[class*="messageContent-"] time {
    font-size: .9rem;
}
